async function bindleftCommonSearchdropdown(instance, fieldName) {
    var vm = instance;
    if (fieldName === "BILLER") {
        const url = `reqFrom=all&moduleName=Billing`;
        DataService.GetBillerList(url).then((response) => {
            if (response?.data?.result) {
                let resultData = response.data.result;
                if (typeof resultData === "string") {
                    resultData = JSON.parse(resultData);
                }
                vm.leftSearchFields[0].listOptions = [];
                vm.BillerListData = resultData;

                vm.BillerListData.forEach(itm => {
                    vm.leftSearchFields[0].listOptions.push({
                        name: itm.USERNAME,
                        value: `${itm.USERID}`,
                    });
                });
            }
        });
    }
}

export default { buttons, leftsearchSchema, listActions, bindleftCommonSearchdropdown }; 