                                                <div class="search-btm-btn background-0 text-left form-check-inline">
                                                    <a title="" id="ancSearchSelectedColumnsInSetup" href="" class="btn btn-success mr-1 px-4" data-toggle-tooltip="tooltip" data-original-title="Search"><em class="fa fa-search"></em>
                                                    </a>
                                                    <a href="" title="" id="ancClearSelectedColumnsInSetup" class="btn btn-danger px-4" data-toggle-tooltip="tooltip" data-original-title="Clear"><em class="fa fa-refresh"></em>
                                                    </a>
                                                </div>
                                            </div>
