                                                            <th style="width:10%">
                                                                Unprocess<br>
                                                                <div class="form-group mb-0 float-left">
                                                                    <label class="switch">
                                                                        <input type="checkbox" v-model="allUnprocess" >
                                                                        <span class="slider round">
                                                                            <span class="slider-yes text-left">Yes</span>
                                                                            <span class="slider-no text-right pr-1">No</span>
                                                                        </span>
                                                                    </label>
                                                                </div>
                                                            </th>

                                                            <th style="width:12%">
                                                                Billed /Unbilled<br>
                                                                <div class="form-group mb-0 float-left">
                                                                    <label class="switch">
                                                                        <input type="checkbox" v-model="allBilledUnbilled" >
                                                                        <span class="slider round">
                                                                            <span class="slider-yes text-left">Yes</span>
                                                                            <span class="slider-no text-right pr-1">No</span>
                                                                        </span>
                                                                    </label>
                                                                </div>
