                                                            <th style="width:12%">
                                                                Rate Schedule<br>
                                                                <div class="form-group mb-0 float-left">
                                                                    <label class="switch">
                                                                        <input type="checkbox" v-model="allRateSchedule" >
                                                                        <span class="slider round">
                                                                            <span class="slider-yes text-left">Yes</span>
                                                                            <span class="slider-no text-right pr-1">No</span>
                                                                        </span>
                                                                    </label>
                                                                </div>
                                                            </th>

                                                            <th style="width:12%">
                                                                Billing Rule<br>
                                                                <div class="form-group mb-0 float-left">
                                                                    <label class="switch">
                                                                        <input type="checkbox" v-model="allBillingRule" >
                                                                        <span class="slider round">
                                                                            <span class="slider-yes text-left">Yes</span>
                                                                            <span class="slider-no text-right pr-1">No</span>
                                                                        </span>
                                                                    </label>
                                                                </div>
                                                            </th>

                                                            <th style="width:12%">
                                                                Report<br>
                                                                <div class="form-group mb-0 float-left">
                                                                    <label class="switch">
                                                                        <input type="checkbox" v-model="allReport" >
                                                                        <span class="slider round">
                                                                            <span class="slider-yes text-left">Yes</span>
                                                                            <span class="slider-no text-right pr-1">No</span>
                                                                        </span>
                                                                    </label>
                                                                </div>
                                                            </th>
                                                        </tr>
                                                    </thead>

                                                    <tbody>
                                                        <tr v-for="(c, index) in receivedData" :key="index">
                                                            <td>
                                                                <input type="checkbox" v-model="c.selected">
                                                            </td>

                                                            <td style="width:30%">
                                                                <span v-html="c.contractName"></span>
                                                            </td>
                                                            <td>
                                                                <label class="switch">
                                                                    <input type="checkbox" v-model="c.isFlag">
                                                                    <span class="slider round">
                                                                        <span class="slider-yes">Yes</span>
                                                                        <span class="slider-no">No</span>
                                                                    </span>
                                                                </label>
                                                            </td>

                                                            <td>
                                                                <label class="switch">
                                                                    <input type="checkbox" v-model="c.isInvoice">
                                                                    <span class="slider round">
                                                                        <span class="slider-yes">Yes</span>
                                                                        <span class="slider-no">No</span>
                                                                    </span>
                                                                </label>
                                                            </td>

                                                            <td>
                                                                <label class="switch">
                                                                    <input type="checkbox" v-model="c.isUnprocess">
                                                                    <span class="slider round">
                                                                        <span class="slider-yes">Yes</span>
                                                                        <span class="slider-no">No</span>
                                                                    </span>
                                                                </label>
                                                            </td>

                                                            <td>
                                                                <label class="switch">
                                                                    <input type="checkbox" v-model="c.isBilledUnbilled">
                                                                    <span class="slider round">
                                                                        <span class="slider-yes">Yes</span>
                                                                        <span class="slider-no">No</span>
                                                                    </span>
                                                                </label>
                                                            </td>

                                                            <td>
                                                                <label class="switch">
                                                                    <input type="checkbox" v-model="c.isRateSchedule">
                                                                    <span class="slider round">
                                                                        <span class="slider-yes">Yes</span>
                                                                        <span class="slider-no">No</span>
                                                                    </span>
                                                                </label>
                                                            </td>

                                                            <td>
                                                                <label class="switch">
                                                                    <input type="checkbox" v-model="c.isBillingRule">
                                                                    <span class="slider round">
                                                                        <span class="slider-yes">Yes</span>
                                                                        <span class="slider-no">No</span>
                                                                    </span>
                                                                </label>
                                                            </td>

                                                            <td>
                                                                <label class="switch">
                                                                    <input type="checkbox" v-model="c.isReport">
                                                                    <span class="slider round">
                                                                        <span class="slider-yes">Yes</span>
                                                                        <span class="slider-no">No</span>
                                                                    </span>
                                                                </label>
                                                            </td>                
                                                        </tr>

                                                        <tr v-if="receivedData.length === 0">
                                                            <td colspan="9" class="text-danger text-center">No record(s) found</td>
                                                        </tr>
                                                    </tbody>
                                                </table>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                                <div class="clearfix"></div>
                                <div class="row flex-row-reverse mt-2">
                                    <div class="col-lg-6 text-right">
                                        <div class="search-btm-btn">
                                            <button id="" @click="Save()" class="btn btn-success" style="float:right;margin-left: 10px" title="" data-toggle-tooltip="tooltip"  data-original-title="Save">
                                                <i class="fa fa-save pr-2"></i><span>Save</span>
                                            </button>
                                            <button  @click="Close()" title="" id="" style="float:right;" class="btn btn-danger" data-toggle-tooltip="tooltip" data-original-title="Cancel">
                                                <em class="fa fa-close pr-2"></em>Cancel
                                            </button>
                                        </div>
                                    </div>
                                    <div class="col-lg-6">
                                        <div class="py-2">
                                            <span class="mandatory">Fields marked with an asterisk (*) are mandatory.</span>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
        <AvailableContract v-if="isAddContract" @submit-data="handleChildSubmit"></AvailableContract>
    </div>
</div>
</template>

<script>
import DataService from '../../services/DataService';
import AvailableContract from '../Biller/AvailableContract.vue';

export default {
    components: {
        AvailableContract
    },
    props: {
        GroupBy: {
            type: String,
            required: false,
        },
        editPayload:{
            type:Object,
            required: false,
        }
    },
    computed: {
        allFlag: {            
            get() {
                if (!this.receivedData.length) return false;
                return this.receivedData.every(c => c.isFlag === true);
            },
            set(value) {
                this.receivedData.forEach(c => {
                    c.isFlag = value;
                });
            }
        },

        allInvoice: {
            get() {
                if (!this.receivedData.length) return false;
                return this.receivedData.every(c => c.isInvoice === true);
            },
            set(value) {
                this.receivedData.forEach(c => {
                    c.isInvoice = value;
                });
            }
        },

        allUnprocess: {
            get() {
                if (!this.receivedData.length) return false;
                return this.receivedData.every(c => c.isUnprocess === true);
            },
            set(value) {
                this.receivedData.forEach(c => {
                    c.isUnprocess = value;
                });
            }
        },

        allBilledUnbilled: {
            get() {
                if (!this.receivedData.length) return false;
                return this.receivedData.every(c => c.isBilledUnbilled === true);
            },
            set(value) {
                this.receivedData.forEach(c => {
                    c.isBilledUnbilled = value;
                });
            }
        },

        allRateSchedule: {
            get() {
                if (!this.receivedData.length) return false;
                return this.receivedData.every(c => c.isRateSchedule === true);
            },
            set(value) {
                this.receivedData.forEach(c => {
                    c.isRateSchedule = value;
                });
            }
        },

        allBillingRule: {
            get() {
                if (!this.receivedData.length) return false;
                return this.receivedData.every(c => c.isBillingRule === true);
            },
            set(value) {
                this.receivedData.forEach(c => {
                    c.isBillingRule = value;
                });
            }
        },

        allReport: {
            get() {
                if (!this.receivedData.length) return false;
                return this.receivedData.every(c => c.isReport === true);
            },
            set(value) {
                this.receivedData.forEach(c => {
                    c.isReport = value;
                });
            }
        }
    },
    watch: {
        editPayload: {
            immediate: true,
            handler(payload) {
                if (!payload) return;
                this.GetAssignBillerById(payload.AssignBiller[0]);                
            }
        }
    },
    data() {
        return {
            isLoading: false,
            companyId: null,
            userId: null,
            isAddContract: false,
            ContractBillerListData: [],
            BillerListData: [],
            AssignBillerData: [],
            receivedData: [],
            billerId:0,
            ClientItemsList: [{
                clientId: 0,
                biller: '',
                isFlag: false,
                isInvoice: false,
                isUnprocess: false,
                isBilledUnbilled: false,
                isRateSchedule: false,
                isBillingRule: false,
                isReport: false
            }],
            AvailableContractData: [
                {
                    clientId: 0,
                    contractName: '',
                    checked: false,
                    isFlag: false,
                    isInvoice: false,
                    isUnprocess: false,
                    isBilledUnbilled: false,
                    isRateSchedule: false,
                    isBillingRule: false,
                    isReport: false
                }
            ],

            FormSchema: [{
                layoutType: "triple",
                Data: [{
                        astype: "MultiSelectField",
                        label: this.$t('Biller'),
                        name: "Biller",
                        value: "",
                        mode: "tag",
                        placeholder: this.$t('Biller'),
                        visibility: true,
                        disabled: false,
                        config: {
                            options: [],
                            //onChange: this.onChangeBiller,
                        },
                        validationRules: {
                            "required": false
                        },
                    },

                ]
            }]
        }
    },
    created: async function () {
        var vm = this;
        vm.userId = vm.GetUserInfo.ID;
        vm.companyId = vm.GetUserInfo.CompanyId;
        await vm.GetBillerList();        
   },
    methods: {
        GetBillerList() {
            var vm = this;
            var url = `reqFrom=all&moduleName=Billing`;
            DataService.GetBillerList(url).then((response) => {
                if (response.status === 200) {
                    if (response?.data?.result) {
                        let resultData = response.data.result;
                        if (typeof resultData === "string") {
                            resultData = JSON.parse(resultData);
                        }
                        if (Array.isArray(resultData) && resultData.length > 0) {
                            vm.BillerListData = resultData;
                            vm.FormSchema[0].Data[0].config.options = [];
                            vm.BillerListData.forEach(element => {
                                let Obj = {
                                    name: element.USERNAME,
                                    value: `${element.USERID}`
                                };
                                vm.FormSchema[0].Data[0].config.options.push(Obj);
                            });
                            vm.$refs.AssignBiller?.UpdateKeyValue();
                        }
                    }
                }
            });
        },

        AddContract() {
            var vm = this;
            vm.isAddContract = true;
        },
        GetAssignBillerById(item){
            var vm=this;
            var biller=vm.GroupBy ? vm.GroupBy : 'Biller';
            var url = `groupId=${item.GroupId}&groupBy=${biller}`;
                DataService.GetAssignBillerById(url).then(response => {
                if (response.status === 200 && response.data?.result) {
                    let resultData = response.data.result;

                    if (typeof resultData === "string") {
                        resultData = JSON.parse(resultData);
                    }

                    // 🔥 push API result back into edit payload
                    vm.handleParentCall({
                        AssignBiller: resultData
                    });
                }
            });
        },
        handleParentCall(payload) {  
            const vm = this;
            if (!payload?.AssignBiller) {
                vm.receivedData = [];
                return;
            }
            // 🔥 Convert object → array if needed
            const list = Array.isArray(payload.AssignBiller)
                ? payload.AssignBiller
                : [payload.AssignBiller];

            vm.receivedData = list.map(c => ({
                clientId: c.CHILD_USER_ID || c.ClientIds,
                contractName: c.CHILD_NAME || c.GroupInfo || c.GroupName,
                selected: true,

                isFlag: Boolean(c.IsFlag),
                isInvoice: Boolean(c.IsInvoice),
                isUnprocess: Boolean(c.IsUnprocess),
                isBilledUnbilled: Boolean(c.IsBilledUnBilled ?? c.IsBilledUnbilled),
                isRateSchedule: Boolean(c.IsRateSchedule),
                isBillingRule: Boolean(c.IsBillingRule),
                isReport: Boolean(c.IsReport),

                parentId: c.PARENT_ID || c.GroupId,
                parentName: c.PARENT_NAME || c.GroupInfo
            }));

            vm.AvailableContractData = vm.receivedData;
            vm.billerId = (payload.AssignBiller[0].GroupId); 

            setTimeout(() => {
                vm.FormSchema[0].Data[0].disabled=true;
                if (!vm.billerId || !Array.isArray(vm.BillerListData)) return;
                const biller = vm.BillerListData.find(
                    x => x.USERID == vm.billerId
                );
                if (!biller) { console.warn('Biller not found in BillerListData', vm.billerId);  return; }
                vm.FormSchema[0].Data[0].value = [
                    {
                        value: biller.USERID,
                        label: biller.USERNAME
                    }
                ];
                vm.$refs.AssignBiller?.UpdateKeyValue();
            }, 200);         
        },

       handleChildSubmit(payload) {
            const vm = this;

            if (!payload || !Array.isArray(payload.AssignBiller)) {
                vm.receivedData = [];
                return;
            }
            vm.receivedData = payload.AssignBiller.flatMap(parent =>
                (parent.Children || []).map(child => ({
                    clientId: child.ChildUserId,
                    contractName: child.ChildName,
                    selected: true,

                    // default flags (or map if backend sends later)
                    isFlag: true,
                    isInvoice: true,
                    isUnprocess: true,
                    isBilledUnbilled: true,
                    isRateSchedule: true,
                    isBillingRule: true,
                    isReport: true,

                    parentId: parent.ParentId,
                    parentName: parent.ParentName
                }))
            );

            vm.AvailableContractData = vm.receivedData;
            vm.isAddContract = false;
        },

      
        Save() {
            const vm = this;
            if (!vm.receivedData.length) {
                 vm.ShowAlert(vm.$t("Selectanyrecordtodelete"));
                return;
            }
            if (!(vm.FormSchema)[0].Data[0].value.length>0) {
                vm.ShowAlert("Please select Biller", "warning", true);
                return;
            }
            const payload = {
                ClientItemsList: vm.receivedData.map(c => ({
                    clientId: c.clientId,        // CHILD_USER_ID
                    billerId: (vm.FormSchema)[0].Data[0].value, // selected biller

                    isFlag: c.isFlag,
                    isInvoice: c.isInvoice,
                    isUnprocess: c.isUnprocess,
                    isBilledUnbilled: c.isBilledUnbilled,
                    isRateSchedule: c.isRateSchedule,
                    isBillingRule: c.isBillingRule,
                    isReport: c.isReport
                })),

                BillerItemsList: vm.AvailableContractData,
                isEditJsonData: false,
                groupBy: "Biller"
            };           
            var obj = JSON.stringify(payload);
            DataService.SaveAssignBiller(obj).then(response => {
                debugger;
                if (response.data) {
                        const status = response.data.status || response.data.Status;
                        if (status === "Success") {
                            vm.ShowAlert(vm.$t('AddedSuccess', [vm.$t('Biller')]),"success",true,vm.$t('Alert'));
                            vm.$parent.FetchData();
                            vm.Close();
                        }
                        else {
                            vm.ShowAlert(response.data.msg || vm.$t("ErrorWhileSaving", [vm.$t("Biller")]),"danger",true,vm.$t("Alert"));
                        }
                        vm.isLoading = false;
                    }                    
                });
        },

        Delete() {
            const vm = this;
            const selectedItems = vm.receivedData.filter(c => c.selected);

            if (!selectedItems.length) {
                vm.ShowAlert(vm.$t("Selectanyrecordtodelete"), "warning", true);
                return;
            }
            vm.confirmR(vm.$t("ConfirmDelete"),true,vm.$t("Delete"),
                function () {
                    vm.receivedData = vm.receivedData.filter(c => !c.selected);
                }
            );
        },
        Close: function () {
            this.$parent.isAddBiller = false;
        },        

    },
}
</script>
<style>

.multiselect__content-wrapper{
    z-index: 99999 !important;
}
#visiblecolumnSelected  .table-fix-header thead {
        position: relative;
        z-index: 2;
    }
</style>